"""
A simple wrapper for invoke tracetool.py

similiar to external/qemu/android-qemu2-glue/build/configure.sh:

generate_trace() {
  local OUT=$1
  local GROUP=$2
  local FORMAT=$3
  local TRACEFILE=$4
  log "GEN $OUT"
  mkdir -p $(dirname $QEMU2_AUTOGENERATED_DIR/$OUT)
  python $QEMU2_TOP_DIR/scripts/tracetool.py \
    --group=$GROUP --format=$FORMAT --backends=nop $TRACEFILE > $QEMU2_AUTOGENERATED_DIR/$OUT || panic "Failed to generate trace $OUT from $TRACEFILE"
}

exmaple usage:

cd external/qemu
scripts/tracetool_wrapper.py --out trace-root.c --group root --format c --tracefile trace-events

"""

from __future__ import print_function
import argparse
import os.path
import subprocess
import sys

def main(argv):
  
  parser = argparse.ArgumentParser()
  parser.add_argument("--out",
                      help="Output file for the generated code.")
  parser.add_argument("--group",
                      help="Name of the event group.")
  parser.add_argument("--format",
                      help="Format for generated code.")
  parser.add_argument("--tracefile",
                      help="Trace file.")

  options = parser.parse_args()

  path = os.path.realpath(options.out)

  output_file = open(path, "w")

  # make sure tracetool.py and current tracetool_wrapper.py are in the same folder
  dirname = os.path.dirname(sys.argv[0])

  cmd = os.path.join(dirname, "tracetool.py")
  cmd += " --group="
  cmd += options.group

  cmd += " --format="
  cmd += options.format

  cmd += " --backends=nop "

  cmd += options.tracefile

  p = subprocess.Popen(cmd, shell=True, universal_newlines=True, stdout=output_file)
  ret = p.wait()
  output_file.flush()

  if ret != 0:
    if ret <= -100:
      # Windows error codes such as 0xC0000005 and 0xC0000409 are much easier to
      # recognize and differentiate in hex. In order to print them as unsigned
      # hex we need to add 4 Gig to them.
      error_number = "0x%08X" % (ret + (1 << 32))
    else:
      error_number = "%d" % ret
    raise RuntimeError("tracetool has returned non-zero status: "
                       "{0}".format(error_number))


if __name__ == "__main__":
  try:
    main(sys.argv)
  except RuntimeError as e:
    print(e, file=sys.stderr)
    sys.exit(1)

